local LBattleHudCacheItem = classX("LBattleHudCacheItem", LBattleObjCache)

function LBattleHudCacheItem:ctor(key)
    LBattleObjCache.ctor(self)


    self.key = key

    ---@type Transform
    self.hudTrans = nil
    ---@type GameObject
    self.hudGameObj = nil

    ---@type number 显示节点 0 ， 伤害 1 ， buff 2， 技能名字3
