end

function LBattleHudCacheItem:SetHudGameObj(gameObj)
    self.hudGameObj  = gameObj
    self.hudTrans = gameObj.transform
end

function LBattleHudCacheItem:SetItemType(itemType)
    self.itemType = itemType
end

function LBattleHudCacheItem:ChangeParent(parent)
    self.hudTrans:SetParent(parent)
end

function LBattleHudCacheItem:SetVisible(bVisible)
