---@region ---缓存容器
---@class LBattleHudCacheMap
local LBattleHudCacheMap = classX("LBattleHudCacheMap", nil)

function LBattleHudCacheMap:ctor()
    self._cacheMap = {}
end

------------------------------------------------------------------
function LBattleHudCacheMap:GetCache(cacheKey, getFunc, selfObj, arg1, arg2)
    local cacheMap = self._cacheMap
    local objList = cacheMap[cacheKey]
    if not objList then
        objList = {}
        cacheMap[cacheKey] = objList
    end
    if #objList == 0 then
        return getFunc(selfObj, cacheKey, arg1, arg2)
    end
    return table.remove(objList)
end

-----------------------------------------------------------------
function LBattleHudCacheMap:ReleaseCache(cacheKey, cache)
    local cacheMap = self._cacheMap
    local objList = cacheMap[cacheKey]
    if not objList then
        objList = {}
        cacheMap[cacheKey] = objList
    end
    table.insert(objList, cache)
end

-----------------------------------------------------------------
function LBattleHudCacheMap:Dispose()
    if self._isDisposed then
        return
    end

    for _,objList in pairs(self._cacheMap) do
        for k,v in ipairs(objList) do
            v:Dispose()
        end
    end
    table.dispose(self)
    self._isDisposed = true
end
---@endregion ---缓存容器


